  ('aboriginal-7fec267e-moex-00274', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '根據山坡地保育利用條例第37條，原住民取得原住民保留地所有權，如有移轉，以原住民為限，但 有特定情形者，得由政府承受私有原住民保留地，下列何者屬於得由政府承受私有原住民保留地之特 定情形？', '["興辦依土地徵收條例第3條（因公益需要之徵收）、第4條第1項（區段徵收）規定之各款事業及 所有權人依該條例第8條規定申請一併徵收", "經中央原住民族主管機關審認符合轉換作為傳統領域土地之需求", "稅捐稽徵機關受理以原住民保留地抵繳增值稅", "因私法金錢給付義務之執行事件未能拍定原住民保留地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00275', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '原住民保留地經劃定為禁伐區域，其具原住民身分之所有權人或合法使用權人，得申請禁伐補償。下 列那一項非屬由主管機關將原住民保留地劃定為禁伐區域並公告之條件？', '["依法編定為林業用地或適用林業用地管制", "依法劃設為保護區或水源特定區", "依法劃設為原住民特定區域計畫範圍", "依法劃設為國家公園之區域"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00276', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '依照原住民族語言發展法，首次將原住民族語言列為國家語言，下列何者不是此法案的立法目的？', '["為實現歷史正義", "推動原住民族自治", "促進原住民族語言之保存與發展", "保障原住民族語言之使用及傳承"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00277', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '因為下列那一個法規立法，最近許多原住民族族人都在直轄市、縣（市）主管機關轄下被聘用擔任專 職族語老師，傳承族語文化？', '["原住民族教育法", "國家語言發展法", "原住民族語言發展法", "通用語言文字法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00278', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '國家語言發展法和原住民族的語言保存與發展息息相關，下列關於國家語言發展法的敘述，何者錯誤？', '["學校教育得使用各國家語言為之", "本法所稱國家語言，指臺灣各固有族群使用之自然語言，但不包含手語", "國民參與政府機關（構）行政、立法及司法程序時，得使用其選擇之國家語言", "政府機關（構）應於必要時提供各國家語言間之通譯服務，並積極培育各國家語言通譯人才"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00279', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '根據原住民族基本法，下列那一項目前不是原住民族在原住民族地區及經中央原住民族主管機關公告 之海域依法可從事的非營利行為？', '["獵捕野生動物及採集野生植物及菌類", "採取礦物、土石", "使用空拍機監測公告海域漁類", "利用水資源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00280', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '下列對原住民族基本法第21條的諮商同意權那一項是不正確的？', '["政府或私人於原住民族土地或部落及其周邊一定範圍內之公有土地從事土地開發、資源利用、生態 保育及學術研究，應諮商並取得原住民族或部落同意或參與，原住民得分享相關利益", "政府或法令限制原住民族利用前項土地及自然資源時，應與原住民族、部落或原住民諮商，並取得 其同意", "政府或法令限制原住民族利用前項土地及自然資源時，受限制所生之損失，應由該主管機關寬列預 算補償之", "政府或法令限制原住民族利用前項土地開發及自然資源營利所得，應提撥一定比例給當地原民教會 或實驗學校，作為回饋經費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00281', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '原住民族教育法在 108 年修正時有 5 大重點，包括擴大原住民族教育對象到全民、完備行政支持系 統、促進原住民族參與、強化師資培育與深化民族教育。下列何者不是該法條內容？', '["各級教育主管機關推動教育政策，應促進全體國民認識與尊重原住民族", "各級教育主管機關並得鼓勵、補助非營利之機構、法人或團體，對社會大眾進行原住民族及多元文 化教育", "政府機關、公營事業機構及政府捐助基金累計超過百分之五十之財團法人，應規劃實施原住民族及 多元文化教育相關課程或活動，並鼓勵其員工參與", "各級政府對於原住民族教師團體及人員，應予獎勵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00282', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '依照原住民族工作權保障法，有關公共工程及政府採購之保障，下列何者正確？', '["各級政府機關、公立學校及公營事業機構，辦理位於原住民地區政府採購法公告金額之採購，應由 原住民個人、機構、法人或團體承包", "各級政府機關、公立學校及公營事業機構，辦理位於原住民地區未達政府採購法公告金額之採購， 應由原住民個人、機構、法人或團體承包。但原住民個人、機構、法人或團體無法承包者，不在此限", "各級政府機關、公立學校及公營事業機構，辦理位於原住民地區之政府採購應由原住民或新住民個 人、機構、法人或教會團體輪流承包", "各級政府機關、公立學校及公營事業機構，辦理位於原住民地區之政府採購應由原住民合作社、原 住民青年、婦女團體承包"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00283', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-111-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '依照原住民族工作權保障法，中央主管機關應於原住民族綜合發展基金項下設置就業基金，作為辦理 促進原住民就業權益相關事項；其收支、保管及運用辦法，由行政院定之。下列何者不是前項就業基 金之來源？', '["政府循預算程序之撥款", "各級政府機關、公立學校及公營事業機構僱用、進用原住民之人數未達所定比例者，依規定所繳納 之代金", "原住民族綜合發展基金之孳息收入", "雇主聘僱移工繳納的就業安定基金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:02+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "501", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL)
